  (10, '1 Timothy 3:16', 34),
  (11, 'John 12:31', 35),
  (11, 'John 14:30', 36),
  (11, 'Colossians 2:15', 37),
  (11, 'Hebrews 2:14', 38),
  (11, 'Revelation 20:10', 39),
  (12, '1 Corinthians 3:1-2', 40),
  (12, 'Hebrews 5:11-14', 41),
  (12, 'Mark 4:33', 42),
  (13, 'John 14:26', 43),
